(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[6705],{9773:(e,n,s)=>{"use strict";s.r(n),s.d(n,{data:()=>l});const l={key:"v-c61afda6",path:"/pages/fe-sre/package-json/",title:"",lang:"zh-CN",frontmatter:{home:!1},excerpt:"",headers:[{level:2,title:"package.json 知识点",slug:"package-json-知识点",children:[{level:3,title:"peerDependencies",slug:"peerdependencies",children:[]},{level:3,title:"bundledDependencies",slug:"bundleddependencies",children:[]},{level:3,title:"optionalDependencies",slug:"optionaldependencies",children:[]},{level:3,title:"package.json的脚本勾子",slug:"package-json的脚本勾子",children:[]}]}],filePathRelative:"pages/fe-sre/package-json/README.md",git:{updatedTime:1721965673e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:2}]}}},5436:(e,n,s)=>{"use strict";s.r(n),s.d(n,{default:()=>u});var l=s(6252);const a=(0,l.Wm)("h2",{id:"package-json-知识点"},[(0,l.Wm)("a",{class:"header-anchor",href:"#package-json-知识点"},"#"),(0,l.Uk)(" package.json 知识点")],-1),p=(0,l.Wm)("h3",{id:"peerdependencies"},[(0,l.Wm)("a",{class:"header-anchor",href:"#peerdependencies"},"#"),(0,l.Uk)(" peerDependencies")],-1),i=(0,l.Uk)("用于指定当前包所依赖的其他包的版本要求，主要目的是通知用户或工具（如 npm 或 yarn）当前包需要特定版本的依赖包才能正常工作。"),t=(0,l.Wm)("br",null,null,-1),r=(0,l.Uk)(" 这些依赖并不会在安装当前包时自动安装，而是需要用户手动安装符合版本要求的依赖。 "),c={href:"https://zhuanlan.zhihu.com/p/666454541",target:"_blank",rel:"noopener noreferrer"},o=(0,l.Uk)("对等依赖"),d=(0,l.uE)('<h3 id="bundleddependencies"><a class="header-anchor" href="#bundleddependencies">#</a> bundledDependencies</h3><p>用于指定一组包，这些包应该与你的包一起打包分发。这些包会被包含在你的包的发布版本中，这样，当其他开发者安装你的包时，他们也会得到这些依赖包的副本。</p><h3 id="optionaldependencies"><a class="header-anchor" href="#optionaldependencies">#</a> optionalDependencies</h3><p>用于指定一组包，这些包是可选的依赖。这些依赖在安装过程中会被尝试安装，但如果安装失败，npm 或 yarn 不会将此作为错误处理，而是继续安装其他依赖。</p><h3 id="package-json的脚本勾子"><a class="header-anchor" href="#package-json的脚本勾子">#</a> package.json的脚本勾子</h3><p>在 package.json 文件中，你可以定义多种脚本钩子 <code>（scripts）</code>，这些脚本钩子可以在特定的 npm 事件发生时自动执行。以下是一些常见的脚本钩子：</p><ul><li>prepublish: 在包发布之前运行，通常用于构建或打包代码。</li><li>prepare: 在包打包或发布之前运行，通常用于确保包的发布版本是正确构建的。</li><li>prepublishOnly: 类似于 prepublish，但是在 npm publish 之前运行，而不是 npm install。</li><li>preinstall: 在安装任何包之前运行，包括 npm install 和 npm ci。</li><li>install: 在安装包之后运行。</li><li>postinstall: 在安装包之后运行，包括 npm install 和 npm ci。</li><li>preuninstall: 在卸载包之前运行。</li><li>uninstall: 在卸载包之后运行。</li><li>postuninstall: 在卸载包之后运行。</li><li>preversion: 在更改包版本之前运行。</li><li>version: 在更改包版本之后运行。</li><li>postversion: 在更改包版本之后运行。</li><li>pretest, test, posttest: 分别在运行测试之前、运行测试时、运行测试之后执行。</li><li>prestop, stop, poststop: 分别在停止命令之前、停止命令时、停止命令之后执行。</li><li>prestart, start, poststart: 分别在启动命令之前、启动命令时、启动命令之后执行。</li><li>prefetch, fetch, postfetch: 分别在获取资源之前、获取资源时、获取资源之后执行。</li></ul><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n    <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;module&quot;</span> <span class="token comment">// 指定当前包是 ECMAScript 模块。</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div>',8),u={render:function(e,n){const s=(0,l.up)("OutboundLink");return(0,l.wg)(),(0,l.j4)(l.HY,null,[a,p,(0,l.Wm)("p",null,[i,t,r,(0,l.Wm)("a",c,[o,(0,l.Wm)(s)])]),d],64)}}}}]);